import{c as p,Q as a,j as i,m as c}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"关于他对待诸位大人的想法","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/41-关于他对待诸位大人的想法.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/41-关于他对待诸位大人的想法.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/upper/41-关于他对待诸位大人的想法.md"};function t(l,e,o,_,s,m){return a(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="关于他对待诸位大人的想法" tabindex="-1">关于他对待诸位大人的想法 <a class="header-anchor" href="#关于他对待诸位大人的想法" aria-label="Permalink to &quot;关于他对待诸位大人的想法&quot;">​</a></h1><p>关于他对待诸位大人的想法和意图，公爵的言辞总是一成不变，充满 良好意愿。我已经写过多次，他每次说到这个主题都是得体合理，声情并 茂，如果他说的都是真的，那么我们就可以高枕无忧了。但是，发生在他 人身上的事情应该让人担心自己的处境；当公爵向诸位大人提出双方达成 某种安排时，诸位大人必须三思而后行，因为公爵阁下显然希望恢复他对 佛罗伦萨旧的服役合约，当他发现还没有机会这样做的时候，他总是转移 话题，举重若轻地将其一带而过，他说建立一种宽泛的联盟对他而言就足 够了，就好像他清楚地看到他现在还无法强迫你们接受，而愿意等待时 机，直到他能够这样做。看来他是认为他可以非常便利地拖延下去，因为 诸位大人显然不会与他作对，考虑到法国的缘故，也考虑到他敌人的状况 和你们自身的弱点，因此，将此事拖下去对他是有利的。不管从此事推论 出什么,我只想提醒诸位大人，公爵发动的这场针对锡耶纳的战事很可能 会成功，这个时刻正在来临，他将看到他一直期待并且处心积虑谋划的那 个机会就要到了。我谦卑地提醒诸位大人，如果我了解的情况有什么不 妥，这是由于我经验不足，无法看到这里以外发生的事情，以及我所得出 的结论无法超出我在上面所谈到的那些内容。我现在将此事留给诸位大人 以你们的睿智英明来判断，向诸位大人致意。今天晚上，有人透露消息， 某些蒙泰普尔恰诺人的代表秘密地来到这里；我将设法知道更多的具体细 节，并将此事通知诸位大人。</p><p>1502/1503年1月8日，发自阿色西 仆尼科洛 · 马基雅维利 我在写给诸位大人的信中，谈到过戈洛 ·达 ·皮斯托亚大人，他现在 就囚禁在这里，有可能需要一笔200达克特的赎金，也许更少，就可以交 到诸位大人手里，我等着诸位大人对此事的回复。</p><p>信件50</p><p>杰出的诸位大人： 我的上一封写于8日的信发自阿色西。我们昨天来到了托尔斯亚诺， 一个距离佩鲁贾4英里的地方，我们明天将离开此地，朝距离此地12英 里、前往锡耶纳的方向的斯佩达莱托前进。我在我的上一封信中写到过 那些身边发生的事情，以及一直没有收到诸位大人对我自上月28日以后 寄出的信件的回复，要不是公爵阁下派人来问我最近是否收到你们的来信 的话，我今天本来不打算写信了。于是，我亲自拜访他，当公爵阁下问我 是否收到诸位大人的信时，我回答说没有，他对此表现得非常惊讶，我当 然没有忘记用那些合理的理由向他解释这个延误。然后，公爵将这个话题 放到一边，他对我说： “你知道我对你们那些大人怀有怎样的良好愿望， 我将你们看成是在意大利支持我的邦国的最主要的基石之一，正因为这 个 ，我的所有内政外交举措和活动都不会对执政团隐瞒。你看到了，我是 如何对付那些执政团和我本人共同的敌人的，他们或是被杀，或是被擒， 或是逃亡，或是被围困在家中；就像对付这个潘多尔福 ·彼得鲁奇，将是 我们这场战事的最后努力，然后，我们将实现共同的安全。将他从藏身之 地赶走非常必要，因为众所周知，此人才干出众又财大气粗，藏身的锡耶 纳拥有足够的资源；一旦他在那里落地生根，就像是星星之火，最终将成 燎原之势；因此，在这个问题上，我们现在还不能回去睡觉，甚至还要全 力以赴地对他穷追猛打。将他从锡耶纳赶走对我来说并不困难，但我希望 他落到我手里。〈正因为这个，教皇为了稳住他，给他颁发了谕令，向他 证明只要他成为教皇敌人的敌人就足够了；与此同时，我率领我的军队前 进，欺骗那些被称为是‘背叛大师’的人真是太好了。〉那些锡耶纳的代 1 表，他们是在巴利阿的名义下来到我这里的，向我很好地保证，而我也向 他们清楚地声明，我并不想剥夺锡耶纳人的自由，而只是希望驱逐潘多尔 福；我已经写了一封信给锡耶纳市政府，澄清我的意图，他们应该在佩鲁</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>贾和卡斯泰洛的事情中得到充分的例证，我将那两座城市都交给了教会， 并没有将它们留在自己手里；此外，我们共同的主人法国国王，也不会允 许我将锡耶纳据为己有，我不会轻率鲁莽到不听劝告如此而行；因此，锡 耶纳人应该有信心，我不想要他们的任何东西，只想将潘多尔福赶走。我 希望你们的大人公布并见证我的想法，我只要他们向我保证交出那位暴 君。我相信锡耶纳的市政当局会相信我，但如果他们不相信我的话，我将 不得不采取非常手段，把大炮架在城门之上， 以武力作为最后手段，驱逐 潘多尔福。我想将这些事情说清楚，以便你们的大人能够明白我的意思； 这样，〈如果他们听说教皇给潘多尔福写过一份谕令，他们可以知道这么 做的真正目的〉。我已经下定决心，在夺取我那些敌人的武装之后，我还 要去掉他们的头脑，包括潘多尔福及其阴谋作乱者。①除此之外，我还想 请求你们执政团，在我对付这个潘多尔福需要某种帮助的时候，为了我的 利益愿意提供援助。我的确相信，如果有谁在一年前向你们的执政团承诺 杀掉维泰洛佐和奥利韦尔罗托、破灭奥尔西尼家族、赶走詹保罗和潘多尔 福，向执政团要100000达克特，他们一定会跑着去奉上。现如今，这一切 都如此彻底干净地解决了，无需他们承担任何代价、努力和辛劳；执政团 尽管没有书面的义务，也有默会的义务。因此，要求执政团支付费用是合 情合理的，这样一来，无论是我还是其他人都会觉得，佛罗伦萨共和国没 有背离她的传统和秉性而变得忘恩负义。如果执政团说他们不想违背法国 的保护，你要写信告诉他们，法国国王保护的是锡耶纳城邦，而不是潘多 尔福；即使潘多尔福曾享有那种保护，但由于他结党营私，反对我和国王 陛下，自然也就失去了那种保护。因此，如果他们没有及时赶来参加这场 战斗，那些大人不会有任何理由为自己开脱；执政团应该更加心甘情愿地 前来援助，而且这对于他们也有利，满足他们复仇的愿望，对于法国国王 也同样有利。对他们的好处是， 一劳永逸地消灭佛罗伦萨共和国的永久的 ①“敌人的武装”指维泰利家族和奥尔西尼家族，“敌人的头脑”指潘尔多福 ·彼得鲁奇，彼得鲁奇被 认为是反公爵阴谋的策划者。——中译者注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>敌人，他总是煽动所有其他的敌人，策动所有那些试图给共和国带来灾祸 的人；满足他们复仇的愿望，是因为潘多尔福是诸多折磨你们共和国这么 多年的心腹大患的罪魁祸首，此人出钱出力，处心积虑地侵犯你们，危害 程度呢?危及执政团的所有领土甚至他们的自由。如果一个人不愿意对那 些事情复仇、不愿意抓住这样一个机会的话，那么就证明他对任何事情都 是麻木的，每天都应遭到别人的唾弃。对法国国王的好处是尽人皆知的， 因为一旦潘多尔福被消灭，我和执政团对我们各自邦国的安全就不再有任 何担心了，在法国国王陛下需要我们的任何时候，我们都能够调集部队前 往那不勒斯或伦巴第；然而，只要潘多尔福仍在锡耶纳，我们就无法对我 们各自的邦国感到安全。法国国王对于所有这些事情都了如指掌，有着深 刻见地，因此，一旦此事成功，他将会欣喜若狂，并万分感激促成此事之 人；如果我知道这件事只对我个人有利，我会更加不遗余力地游说你们， 然而，由于这关系到我们的共同利益，我把话说到这里就足够了。而且， 我说这番话不是因为我不相信自己，不能依靠我自己的力量完成这个行 动，而是希望整个意大利都确信我们之间的联盟关系，并因此提升我们每 一方的声誉。”这样，公爵要求我写下这番话，报告给你们，并希望你们 能够尽快答复，而我写给诸位大人的内容几乎就是公爵的原话。 我们谈到那不勒斯王国的事情，公爵对我说，西班牙人在一次伏击中 杀死了30名法国重骑兵，然而，这只是一个微不足道的小事件；在德意志方 面，尚未听到任何风声。国王陛下对于肖蒙大人召回他的部队非常不满，对 于肖蒙大人所采取的反对公爵阁下的措施，国王一再表示了个人愤怒。 向诸位大人致意。再会!</p><p>发自托尔斯亚诺，1502/1503年1月10日 仆尼科洛 · 马基雅维利，国务秘书 请诸位大人付给送信人10里拉，并报销给比亚焦5达克特，这是我在 上个月寄出的3封信的邮费。</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>附注：一名为公爵效力的西班牙队长唐米凯莱今天突然对我像魔鬼一 样发火，他说他在皮翁比诺写的信以及那些寄给他的信都被开封了；并 且，佛罗伦萨关卡的关税员改动了他派往皮翁比诺的步兵数量。我请求诸 位大人卸下我背上的重担，采取措施纠正第一件事，并给第二件事以合理 的解释，免得我背负骂名。</p><p>信件51</p><p>杰出的诸位大人： 今天早上，我们离开了昨天晚上住宿的斯佩达莱，有一名安东尼 奥 · 贾科米诺的弓箭手加入我们的队伍，他交给我一封诸位大人写于5日 的信，这封信让我相当懊悔，你们并没有收到我关于所发生事件的任何 报告!然后，我们到达了这里，拉布洛 · 特索给我带来你们写于9日的信 件，这些信让我感到同样的懊悔，信中显示你们只收到了我写于本月1日 和2日的2封信。看来这是真的，我的所有努力在最需要的时候却化为乌 有，而我本应该因为这些努力而获得更好的评价。像诸位大人这样谨慎睿 智的人一定明白，一个人仅仅恪尽职守是不够的，还必须要有好的运气； 如果手头能够找到的话，我非常愿意将所有这些信件的副本寄给诸位大 人，但我找不到了，鉴于我现在所处的时间和地点，我只能简短地复述一 下。在上个月的最后一天，我写了2封信， 一封信写于23点，讲述了奥尔 西尼家族的人和维泰利家族的人被捕的情形；另一封信更加详细，包含了 所发生事件的具体细节以及我同公爵阁下的谈话，他在其中表达了对佛罗 伦萨共和国的深情厚谊，而且他使用的亲切友好和谨慎睿智的言辞真是出 乎我的期望。他显示出他完全理解佛罗伦萨的自由与强大对于周边国家 维护它们的权力有多么必要，只要有你们的支持他就会尽全力实现这个目 标。然后，公爵希望我催促诸位大人，在卡斯泰洛和佩鲁贾的事情上能够</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>出动你们的军队为其提供帮助；并且，如果乌尔比诺公爵逃到佛罗伦萨境 内，将其逮捕并监禁起来，但他表示，只要把他留在诸位大人手里不要交 给别人，他就心满意足了。我的下一封信写于2日，发自科利纳尔多，重 复了上述内容，并补充了随后发生的那些事情，正如诸位大人看到的，照 你们信中所写，你们已经收到了那封信。然后，我写于4日的信发自萨索 费拉托、6日的信发自瓜尔多，叙述了卡斯泰洛和佩鲁贾投降，两地的代 表相继来见公爵阁下。我写于8日的信发自阿色西，是关于我所听说的锡 耶纳的代表来见公爵的事情。我写于10日的信发自托尔斯亚诺，报告了公 爵对我说的一番话，表明了他对锡耶纳事件的想法，他说他已经将佛罗伦 萨共和国看成他的邦国最重要的支持，因此，他希望同诸位大人有更为紧 密的交流，不仅在外交方面，还有内政方面。在维泰洛佐和奥利韦尔罗托 命丧黄泉、奥尔西尼家族遭受灭顶之灾及詹保罗被逐逃窜之后，仍有一件 事悬而未决，就是保证公爵自己和诸位大人的安宁，而祸根正是潘多尔 福 ·彼得鲁奇，公爵正试图把他驱逐出锡耶纳城。公爵觉得，这个行动既 是为着他自己的好处，也符合诸位大人的利益，公爵认为非常有必要让诸 位大人在此事上助其一臂之力，因为如果潘多尔福仍留在那里的话，由于 此人的秉性和手中充裕的钱财，以及锡耶纳的丰富资源，恐怕他会以星火 燎原之势将灾祸从一个地方引发到其他地方，此人长期以来都被认为是那 些无法无天的反叛领主们的首领。这样一种事态对你们的伤害远甚于其他 人，公爵认为你们应该更深刻地感受到这一点，而且，有更多的理由让 你们愿意参与此事：首先，维泰洛佐等人之死给诸位大人带来的利益； 其次，你们自己特殊的利益；再次，复仇的愿望；最后，对法国国王的利 益。说到你们应该对公爵心存感激之情，他说如果一年前有人向诸位大人 承诺可以干掉维泰洛佐并扑灭奥尔西尼家族及其支持者的势力，你们肯定 愿意付给那人100000达克特；因此， 一旦这些事情在无需你们承担任何费 用、辛劳和责任的情况下完成了，即使没有书面的义务，诸位大人也对他 有默会的义务；如果诸位大人开始偿还这个义务，那自然很好，否则就违</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>背了你们惯常的做法而显得忘恩负义。至于你们由此得到的好处，据公爵 说是非常巨大的，因为，如果潘多尔福还留在锡耶纳的话，那里将会成为 你们所有敌人的一个藏身之处和据点。至于你们复仇的愿望，公爵说，潘 多尔福在去年夏天阿雷佐事件中挑起了对诸位大人的战争，不但出钱而且 出力，你们寻找机会报这一箭之仇是理所当然的事情，而一旦你们让这样 的机会溜走而毫无悔意，你们将时刻都有可能再次遭受同样的伤害。至于 这件事情对法国国王的好处是这样的， 一旦潘多尔福被赶走，公爵阁下就 消除了后顾之忧，就能够安全地调动他的部队，支持国王在伦巴第和那不 勒斯王国的行动。公爵还说，诸位大人不应该顾虑法国对锡耶纳的保护， 因为保护的是锡耶纳城而不是潘多尔福，而他所进行的是针对潘多尔福的 战争，不是针对锡耶纳人的。他要求我这样给诸位大人写信，以便你们能 够将此事公之于众，并向全世界见证，如果锡耶纳将潘多尔福驱逐出境， 他就不会再插足锡耶纳城内事务，但如果他们拒绝这么做，公爵将不得不 把大炮架在城墙下，逼其就范。公爵再次请求我写信给诸位大人，请求你 们出兵参与这场战事。所有这些事实上都包含在我10日的信中，写于托尔 斯亚诺，我复述了那些内容，担心诸位大人像上几次一样收不到信；希望 诸位大人尽早决定此事，并给我回复。 今天，我收到诸位大人9日的信后，就同公爵阁下进行了面谈，我告 诉他，诸位大人已经准备好，在任何有需要的时候出兵卡斯泰洛；我还告 诉他，佛罗伦萨执政团对于最近发生的事情颇感欣慰，并且已经选出亚科 波 ·萨尔维亚蒂作为大使，不久就将抵达此地。公爵对所有这一切感到非 常高兴，他说他相信诸位大人在他对付潘多尔福的战事中绝不会袖手旁 观，他再次请求我催促诸位大人尽快落实这些事项；他对于这位德高望重 的大使人选非常满意，满怀希望地期待与他会面。然后，我们一起谈了许 多事情，都围绕着潘多尔福的战事，公爵表示他已经下定决心，不惜使用 任何手段，他说他既不缺钱也不缺外部支持。另一方面，罗莫利诺大人昨 天已经启程通过驿道去了罗马，而我从绝对权威的渠道了解到，他此行的</p><p>目的是向教皇陛下咨询对这个战事的意见，询问他如果有可能同潘多尔福 签订一个有利的和约，这么做是否合适；因为公爵认为，如果他同时对付 锡耶纳和奥尔西尼家族，他一定会忙于应付，他判断先将一个放在一边， 对付另一个会更加容易一些，然后他就能回过头来，在适当的时机再对付 那一个。我得到的这个消息可能并不可靠，但这件事并非不合理，尽管与 公爵自己的话相矛盾，他向我表示他要不惜一切代价发动这场对潘多尔福 的战事；如果教皇与潘多尔福和谈，那也是为了把他交到公爵手中，并且 希望通过这种和谈来防止潘多尔福逃亡。我认为，最好还是了解一下每一 件事情，然后再将决定付诸实施。 一整天，人们都在这里忙着造梯子，这是第一批攻城器具，准备架设 在基亚纳河在锡耶纳境内的那一侧，但具体地点尚未可知。 公爵阁下非常热情地接待了一位前来此地的本蒂沃利奥家族的秘书， 他此行的目的是要确认公爵阁下对他们的友好意愿，公爵下令把他与本蒂 沃利奥家族所达成的和平条约在他所有的领地公布出来，这里的兵营也要 如此，以便做到众人皆知。公爵还要求本蒂沃利奥家族派出100重骑兵和 200轻骑兵，这是他们对公爵承担的援助义务。公爵今天也请求我给诸位 大人写信，希望你们能够为前来增援的乔瓦尼大人的这些人马提供通道和补 给，费用由他们承担，我就以公爵的名义向诸位大人提出这样的请求。</p>',19)])])}const h=p(r,[["render",t]]);export{d as __pageData,h as default};
